#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[100005];
        scanf("%s", A);
        int n = strlen(A);
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j <= n; j++) {
                char temp[100005];
                strncpy(temp, A + i, j - i);
                temp[j - i] = '\0';
                int len = strlen(temp);
                if (len == 2 && temp[0] == temp[1]) {
                    count++;
                } else if (len > 2 && temp[0] == temp[len - 1]) {
                    int flag = 1;
                    for (int k = 1; k < len - 1; k++) {
                        if (temp[k] != temp[1]) {
                            flag = 0;
                            break;
                        }
                    }
                    if (flag) {
                        count++;
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

