import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String A = sc.nextLine();
            int n = A.length();
            int count = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j <= n; j++) {
                    String temp = A.substring(i, j);
                    int len = temp.length();
                    if (len == 2 && temp.charAt(0) == temp.charAt(1)) {
                        count++;
                    } else if (len > 2 && temp.charAt(0) == temp.charAt(len - 1)) {
                        int flag = 1;
                        for (int k = 1; k < len - 1; k++) {
                            if (temp.charAt(k) != temp.charAt(1)) {
                                flag = 0;
                                break;
                            }
                        }
                        if (flag) {
                            count++;
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

